import{p as a,bh as i,I as t,U as s}from"./chunks/framework.BpabEsSf.js";const g=JSON.parse('{"title":"WebDAV Backup Format Specification","description":"","frontmatter":{"title":"WebDAV Backup Format Specification","date":"2026-05-01T23:00:00.000Z","permalink":"reference/webdav-backup-specification","categories":["Technical Specifications"],"tags":["WebDAV","Backup","Security"]},"headers":[],"relativePath":"vi/02.Configuration/02.Docs/01.Monica-Android-WebDAV Backup Format Specification.md","filePath":"vi/02.Configuration/02.Docs/01.Monica-Android-WebDAV Backup Format Specification.md","lastUpdated":null}'),c={name:"vi/02.Configuration/02.Docs/01.Monica-Android-WebDAV Backup Format Specification.md"};function e(h,n,p,o,l,r){return i(),t("div",null,[...n[0]||(n[0]=[s(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /vi\\02.Configuration\\02.Docs\\01.Monica-Android-WebDAV Backup Format Specification.md for this page in Markdown format</div><h1 id="📦-monica-webdav-backup-format-specification" tabindex="-1">📦 Monica WebDAV Backup Format Specification <a class="header-anchor" href="#📦-monica-webdav-backup-format-specification" aria-label="Permalink to &quot;📦 Monica WebDAV Backup Format Specification&quot;">​</a></h1><div class="note custom-block"><p class="title note-title custom-block-title">Tóm tắt</p><p>Tài liệu đặc tả này định nghĩa cấu trúc lưu trữ, định dạng dữ liệu cơ bản và các giao thức mã hóa được sử dụng bởi kho lưu trữ cục bộ <code>Monica</code> trong quá trình sao lưu WebDAV tự động và truyền tải dữ liệu. Khung kiến trúc này đảm bảo <strong>khả năng phân tích cú pháp đa nền tảng mạnh mẽ</strong> cùng với <strong>tính riêng tư và bảo mật tuyệt đối không thỏa hiệp</strong>.</p></div><hr><h2 id="_1-tong-quan" tabindex="-1">1. Tổng quan <a class="header-anchor" href="#_1-tong-quan" aria-label="Permalink to &quot;1. Tổng quan&quot;">​</a></h2><p>Cơ chế sao lưu WebDAV của Monica đóng gói dữ liệu cốt lõi của người dùng vào một kho lưu trữ ZIP tiêu chuẩn (<code>.zip</code> khi không mã hóa và <code>.enc.zip</code> khi tính năng mã hóa sao lưu cường độ cao được kích hoạt).</p><p>Thay vì xuất trực tiếp cơ sở dữ liệu nhị phân truyền thống và dư thừa, kho lưu trữ sao lưu áp dụng kiến trúc liên kết lỏng lẻo bao gồm <strong>dữ liệu cốt lõi <code>.json</code></strong>, <strong>bản tóm tắt <code>.csv</code></strong> và <strong>tài nguyên phương tiện (Hình ảnh)</strong>. Điều này đảm bảo việc kiểm toán dữ liệu được đơn giản hóa và quy trình khôi phục có độ chính xác cao trên các nền tảng khác nhau trong tương lai.</p><hr><h2 id="_2-cau-truc-thu-muc-cua-kho-luu-tru-sao-luu" tabindex="-1">2. Cấu trúc thư mục của kho lưu trữ sao lưu <a class="header-anchor" href="#_2-cau-truc-thu-muc-cua-kho-luu-tru-sao-luu" aria-label="Permalink to &quot;2. Cấu trúc thư mục của kho lưu trữ sao lưu&quot;">​</a></h2><p>Cấu trúc cây của một kho lưu trữ ZIP sao lưu tiêu chuẩn sau khi giải nén được mô tả chi tiết dưới đây:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/ (Thư mục gốc)</span></span>
<span class="line"><span>├── passwords/                  # Các bản ghi mật khẩu (lưu trữ riêng biệt có tính kết dính cao)</span></span>
<span class="line"><span>│   ├── password_1_1700000.json</span></span>
<span class="line"><span>│   └── password_2_1700001.json</span></span>
<span class="line"><span>├── notes/                      # Các ghi chú bảo mật (định dạng JSON)</span></span>
<span class="line"><span>│   └── note_101_2026.json</span></span>
<span class="line"><span>├── cards/                      # Bản ghi thẻ tín dụng/thẻ ngân hàng</span></span>
<span class="line"><span>│   └── card_50_visa.json</span></span>
<span class="line"><span>├── otps/                       # Seed và cấu hình xác thực hai yếu tố (2FA TOTP)</span></span>
<span class="line"><span>│   └── otp_201_github.json</span></span>
<span class="line"><span>├── images/                     # Tài nguyên phương tiện và tệp đính kèm nhị phân</span></span>
<span class="line"><span>│   ├── img_hash_9a8b7c.jpg</span></span>
<span class="line"><span>│   └── doc_hash_1f2e3d.pdf</span></span>
<span class="line"><span>├── summary.csv                 # Tập tin mục lục tổng hợp (dùng để xem trước nhanh cấu trúc dòng)</span></span>
<span class="line"><span>└── metadata.json               # Siêu dữ liệu phiên bản sao lưu (dấu thời gian, thông tin client, ID thế hệ)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br></div></div><hr><h2 id="_3-quy-trinh-ma-hoa-nhi-phan-ma-nguon-monica-enc-v1" tabindex="-1">3. Quy trình mã hóa nhị phân mã nguồn (<code>MONICA_ENC_V1</code>) <a class="header-anchor" href="#_3-quy-trinh-ma-hoa-nhi-phan-ma-nguon-monica-enc-v1" aria-label="Permalink to &quot;3. Quy trình mã hóa nhị phân mã nguồn (\`MONICA_ENC_V1\`)&quot;">​</a></h2><p>Khi người dùng kích hoạt tính năng mã hóa sao lưu, tệp ZIP thô sẽ không được ghi trực tiếp lên đĩa. Thay vào đó, nó sẽ được chuyển đổi thành một luồng nhị phân được mã hóa thông qua quy trình sau:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Quy trình đóng gói cục bộ]</span></span>
<span class="line"><span>Bộ dữ liệu JSON cốt lõi trong Sandbox</span></span>
<span class="line"><span>       ⬇</span></span>
<span class="line"><span>[Đóng gói thành luồng ZIP nhị phân tiêu chuẩn]</span></span>
<span class="line"><span>       ⬇</span></span>
<span class="line"><span>[Lấy mật khẩu sao lưu của người dùng] ➔ [Phái sinh khóa PBKDF2 với 100.000 lần lặp]</span></span>
<span class="line"><span>       ⬇</span></span>
<span class="line"><span>[Tiêm mã hóa AES-256-GCM kiên cố]</span></span>
<span class="line"><span>       ⬇</span></span>
<span class="line"><span>[Thêm Header ma thuật MONICA_ENC_V1] ➔ Tạo tệp .enc.zip độc lập ➔ Tải lên WebDAV</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><h3 id="thiet-ke-header-tep" tabindex="-1">Thiết kế Header tệp: <a class="header-anchor" href="#thiet-ke-header-tep" aria-label="Permalink to &quot;Thiết kế Header tệp:&quot;">​</a></h3><p>Header của tệp đóng gói rõ ràng một chuỗi các byte ma thuật độc nhất:</p><ul><li><code>MONICA_ENC_V1</code> (Chỉ báo phiên bản thế hệ định dạng)</li><li>Salt ngẫu nhiên có entropy cao</li><li>Vector khởi tạo ngẫu nhiên (IV)</li></ul><hr><h2 id="_4-chong-phat-lai-khu-tuong-quan-anti-replay-de-correlation" tabindex="-1">4. Chống phát lại &amp; Khử tương quan (Anti-Replay &amp; De-correlation) <a class="header-anchor" href="#_4-chong-phat-lai-khu-tuong-quan-anti-replay-de-correlation" aria-label="Permalink to &quot;4. Chống phát lại &amp; Khử tương quan (Anti-Replay &amp; De-correlation)&quot;">​</a></h2><p>Mỗi thực thể sao lưu độc lập đều tạo ra các salt có entropy cao và các IV duy nhất. Ngay cả khi tải trọng sao lưu (payload) giữa các lần là hoàn toàn giống nhau, cấu trúc nhị phân của các kho lưu trữ <code>.enc.zip</code> kết quả trên đám mây sẽ khác biệt hoàn toàn. Điều này ngăn chặn các nhà cung cấp dịch vụ đám mây phân tích hành vi hoặc lập hồ sơ dữ liệu người dùng thông qua kích thước dấu chân tệp (file footprint sizes).</p><hr><h2 id="_5-logic-khoi-phuc-xuyen-thiet-bi-giam-thieu-xung-đot" tabindex="-1">5. Logic khôi phục xuyên thiết bị &amp; Giảm thiểu xung đột <a class="header-anchor" href="#_5-logic-khoi-phuc-xuyen-thiet-bi-giam-thieu-xung-đot" aria-label="Permalink to &quot;5. Logic khôi phục xuyên thiết bị &amp; Giảm thiểu xung đột&quot;">​</a></h2><p>Trong giai đoạn khôi phục dữ liệu, runtime của client sẽ thực thi nghiêm ngặt vòng đời đường ống (pipeline) tuần tự sau:</p><ol><li><strong>Giải mã &amp; Xác thực</strong>: Giải mã <code>.enc.zip</code> ➔ Xác thực tính toàn vẹn của khối header ➔ Giải mã luồng dữ liệu thông qua các khóa phái sinh từ mật khẩu chủ ➔ Giải nén các tệp vào một sandbox cô lập trong bộ nhớ.</li><li><strong>Giải quyết xung đột ID</strong>:</li></ol><ul><li>Nếu một bản ghi JSON được trích xuất có <code>id</code> trùng với <code>id</code> đã tồn tại trong cơ sở dữ liệu hoạt động của thiết bị, engine sẽ <strong>từ chối việc ghi đè trực tiếp</strong>.</li><li>Kích hoạt tuyến đường dự phòng: Cấp một <code>Long ID</code> vật lý duy nhất mới cho bản ghi mới đến và ghi nó vào cơ sở dữ liệu một cách an toàn.</li></ul><ol start="3"><li><strong>Tái cấu trúc đồ thị quan hệ (Sửa đổi liên kết ID)</strong>:</li></ol><ul><li>Các tiến trình runtime sẽ biên dịch một bảng ánh xạ tạm thời theo dõi các điều chỉnh <code>Old ID ➔ New ID</code>.</li><li>Tự động vá các tham số <code>ssoRefEntryId</code>, các chỉ báo tài khoản liên kết và các ràng buộc TOTP liên quan, giữ cho các liên kết đồ thị toàn vẹn không bị phá vỡ.</li></ul><ol start="4"><li><strong>Di chuyển tài nguyên phương tiện</strong>:</li></ol><ul><li>Xử lý tất cả các bản ghi nhị phân bên trong cây thư mục <code>images/</code>.</li><li>Di chuyển an toàn các ảnh chụp nhanh và tệp đính kèm tài liệu vào không gian hệ thống tệp cục bộ cô lập của ứng dụng lưu trữ (<code>context.filesDir</code>), cập nhật lại các liên kết đường dẫn nội bộ tương ứng trong cơ sở dữ liệu ghi chú đang hoạt động.</li></ul>`,30)])])}const d=a(c,[["render",e]]);export{g as __pageData,d as default};
